import * as functions from "firebase-functions";
import * as admin from "firebase-admin";
import { assertCapability, UserRole } from "../lib/policy";
import { CAPABILITIES } from "../lib/capabilities";

interface AssignRoleData {
  uid: string;
  role: UserRole;
  schoolId?: string | null;
  capabilities?: string[];
}

export const assignRole = functions.https.onCall(
  async (data: AssignRoleData, context: functions.https.CallableContext) => {
    // 1. Otorisasi: Hanya super_admin yang boleh memanggil ini.
    // Kita cek apakah pemanggil punya role super_admin (di handle oleh assertCapability jika kita lempar SYSTEM_CONFIG_MANAGE)
    // Atau karena assignRole sangat krusial, kita bisa cek langsung claims.role
    const claims = assertCapability(context, CAPABILITIES.SYSTEM_CONFIG_MANAGE);

    if (claims.role !== "super_admin") {
      throw new functions.https.HttpsError(
        "permission-denied",
        "Only super_admin can assign roles."
      );
    }

    const { uid, role, schoolId, capabilities } = data;

    if (!uid || !role) {
      throw new functions.https.HttpsError(
        "invalid-argument",
        "The function must be called with a valid uid and role."
      );
    }

    try {
      // 2. Terapkan Custom Claims
      const newClaims = {
        role,
        schoolId: schoolId || null,
        capabilities: capabilities || [],
      };

      await admin.auth().setCustomUserClaims(uid, newClaims);

      // 3. (Opsional) Tulis ke Audit Logs
      // TODO: Panggil helper writeAuditLog setelah diimplementasikan

      return {
        message: `Success setting role ${role} for user ${uid}`,
      };
    } catch (error: any) {
      throw new functions.https.HttpsError("internal", error.message);
    }
  }
);

import * as functions from "firebase-functions";
import * as admin from "firebase-admin";

interface ChangePasswordData {
  newPassword: string;
}

export const changePassword = functions.https.onCall(
  async (data: ChangePasswordData, context: functions.https.CallableContext) => {
    if (!context.auth) {
      throw new functions.https.HttpsError(
        "unauthenticated",
        "Request must be authenticated."
      );
    }

    const uid = context.auth.uid;
    const { newPassword } = data;

    if (!newPassword || newPassword.length < 6) {
      throw new functions.https.HttpsError(
        "invalid-argument",
        "Password must be at least 6 characters long."
      );
    }

    try {
      // 1. Update the password in Firebase Auth
      await admin.auth().updateUser(uid, {
        password: newPassword,
      });

      // 2. Clear the requiresPasswordChange flag in Firestore
      const db = admin.firestore();
      const userRef = db.collection("users").doc(uid);

      await userRef.set({
        requiresPasswordChange: false,
        passwordChangedAt: admin.firestore.FieldValue.serverTimestamp(),
      }, { merge: true });

      return { message: "Password updated successfully." };
    } catch (error: any) {
      throw new functions.https.HttpsError("internal", error.message);
    }
  }
);

import * as functions from "firebase-functions";
import * as admin from "firebase-admin";

interface BootstrapData {
  // We can pass data if needed, but typically first login bootstrap
  // is just setting the flag after verifying something.
  // We'll keep it simple for now.
}

export const firstLoginBootstrap = functions.https.onCall(
  async (data: BootstrapData, context: functions.https.CallableContext) => {
    if (!context.auth) {
      throw new functions.https.HttpsError(
        "unauthenticated",
        "Request must be authenticated."
      );
    }

    const uid = context.auth.uid;

    try {
      // In a real scenario, this function would verify the initial credentials
      // and set the claims. But since assignRole handles claims, this function
      // might just be used to initialize the user's document in Firestore.

      const db = admin.firestore();
      const userRef = db.collection("users").doc(uid);

      await userRef.set({
        requiresPasswordChange: true,
        lastBootstrap: admin.firestore.FieldValue.serverTimestamp(),
      }, { merge: true });

      return { message: "Bootstrap successful, please change password." };
    } catch (error: any) {
      throw new functions.https.HttpsError("internal", error.message);
    }
  }
);

