export async function GET() {
  try {
    const now = Date.now();
    const payload: Record<string, any> = {};

    for (const key in SCHOOLS) {
      const s = SCHOOLS[key];
      payload[key] = {
        ...s,
        adminAccessActive: true,
        isActive: true,
        adminEmail: s.authEmail,
        backupEmail: "",
        createdAt: now,
        updatedAt: now,
      };
    }

    // Use set to write all at once
    await adminDb.ref("schools").set(payload);

    return NextResponse.json({
      success: true,
      message: `Berhasil menginjeksi ${Object.keys(payload).length} sekolah`,
      count: Object.keys(payload).length,
    });
  } catch (e: any) {
    console.error("Seed error:", e);
    return NextResponse.json(
      { success: false, error: e.message, stack: e.stack },
      { status: 500 }
    );
  }
}

