                        placeholder="email kontak login sekolah"
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-semibold tracking-widest text-slate-400">EMAIL KONTAK ADMIN</label>
                      <input
                        value={schoolForm.adminEmail}
