                              >
                                {s.isActive ? "Tutup Tenant" : "Buka Tenant"}
                              </button>
                            </td>
                          </tr>
                        ))}
                        {schools.length === 0 && (
                          <tr>
                            <td colSpan={5} className="px-4 py-10 text-center text-slate-400">
                              Belum ada data sekolah.
                            </td>
                          </tr>
                        )}
                      </tbody>
                    </table>
                  </div>
                </div>
              </div>
            )}

            {activeSection === "monitoring" && (
              <div className="space-y-4">
