import Link from "next/link";
import { useEffect, useMemo, useState } from "react";
import { onValue, ref } from "firebase/database";
import { rtdb as db } from "@/lib/firebase/client";
import { callSuperAdminApi } from "@/lib/callSuperAdminApi";
import { useAuthStore } from "@/store/useAuthStore";

type SchoolRow = {
  schoolId: string;
  name: string;
  district: string;
  npsn: string;
  authEmail: string;
  adminEmail: string;
  backupEmail: string;
  isActive: boolean;
  createdAt?: number | null;
  updatedAt?: number | null;
};

function normalize(value: unknown): string {
  return String(value || "").trim();
}

function normalizeSchoolScope(value: unknown): string {
  return normalize(value).toLowerCase();
}

function formatTs(ts?: number | null): string {
  if (!ts || typeof ts !== "number") return "-";
  return new Date(ts).toLocaleString("id-ID");
}

export default function SuperAdminTenantsPage() {
  const { user, loading: isAuthLoading } = useAuthStore();
  const [q, setQ] = useState("");
  const [rows, setRows] = useState<SchoolRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [busyId, setBusyId] = useState<string>("");
  const [error, setError] = useState("");

  useEffect(() => {
    if (isAuthLoading) return;
    setLoading(true);
    setError("");
    const unsub = onValue(
      ref(db, "schools"),
      (snapshot) => {
        const data = snapshot.val();
        if (!data || typeof data !== "object") {
          setRows([]);
          setLoading(false);
          return;
        }

        const list: SchoolRow[] = Object.entries(data).map(([key, v]: any) => ({
          schoolId: normalizeSchoolScope(v?.schoolId || key),
          name: v?.name ? String(v.name) : "",
          district: v?.district ? String(v.district) : "",
          npsn: v?.npsn ? String(v.npsn) : "",
          authEmail: v?.authEmail ? String(v.authEmail) : "",
          adminEmail: v?.adminEmail ? String(v.adminEmail) : "",
          backupEmail: v?.backupEmail ? String(v.backupEmail) : "",
          isActive: v?.isActive !== false,
          createdAt: typeof v?.createdAt === "number" ? v.createdAt : null,
          updatedAt: typeof v?.updatedAt === "number" ? v.updatedAt : null,
        }));
        list.sort((a, b) => String(a.name || a.schoolId).localeCompare(String(b.name || b.schoolId)));
        setRows(list);
        setLoading(false);
      },
      (e) => {
        setError(String((e as any)?.message || e || "Gagal memuat data schools."));
        setRows([]);
        setLoading(false);
      }
    );
    return () => unsub();
  }, [isAuthLoading]);

  const stats = useMemo(() => {
    const total = rows.length;
    const active = rows.filter((r) => r.isActive).length;
    return { total, active, inactive: Math.max(0, total - active) };
  }, [rows]);

  const filtered = useMemo(() => {
    const query = normalize(q).toLowerCase();
    if (!query) return rows;
    return rows.filter((r) => {
      const hay = [
        r.schoolId,
        r.name,
        r.district,
        r.npsn,
        r.authEmail,
        r.adminEmail,
        r.backupEmail,
      ]
        .map((x) => normalize(x).toLowerCase())
        .join(" ");
      return hay.includes(query);
    });
  }, [q, rows]);

  const toggleActive = async (sid: string, next: boolean) => {
    const schoolId = normalizeSchoolScope(sid);
    if (!schoolId) return;
    setBusyId(schoolId);
    setError("");
    try {
      await callSuperAdminApi("POST", {
        action: "toggle-school-active",
        schoolId,
        nextActive: next,
      });
    } catch (e: any) {
      setError(String(e?.message || e || "Gagal update status sekolah."));
    } finally {
      setBusyId("");
    }
  };

  return (
    <div className="space-y-6">
      <div className="rounded-3xl bg-slate-900/60 p-6 shadow-xl border border-slate-700/50 backdrop-blur-2xl">
        <div className="flex flex-wrap items-start justify-between gap-3">
          <div>
            <h1 className="text-2xl font-bold text-slate-100">Sekolah & Tenant</h1>
            <p className="mt-1 text-sm text-slate-300">
              Kontrol enable/disable tenant sekolah.
            </p>
          </div>
          <Link
            href="/dashboard/super"
            className="inline-flex items-center justify-center rounded-xl border border-slate-700/50 bg-slate-900/40 px-4 py-2 text-sm font-semibold text-slate-100 hover:bg-slate-900/60"
          >
            Kembali
          </Link>
        </div>
      </div>

      <div className="grid gap-4 sm:grid-cols-3">
        <div className="rounded-3xl bg-slate-900/60 p-6 shadow-xl border border-slate-700/50 backdrop-blur-2xl">
          <div className="text-xs font-semibold tracking-widest text-slate-400">TENANTS</div>
          <div className="mt-1 text-2xl font-bold text-slate-100">{stats.total}</div>
          <div className="mt-1 text-sm text-slate-300">Total sekolah</div>
        </div>
        <div className="rounded-3xl bg-slate-900/60 p-6 shadow-xl border border-slate-700/50 backdrop-blur-2xl">
          <div className="text-xs font-semibold tracking-widest text-slate-400">AKTIF</div>
          <div className="mt-1 text-2xl font-bold text-slate-100">{stats.active}</div>
          <div className="mt-1 text-sm text-slate-300">Sekolah aktif</div>
        </div>
        <div className="rounded-3xl bg-slate-900/60 p-6 shadow-xl border border-slate-700/50 backdrop-blur-2xl">
          <div className="text-xs font-semibold tracking-widest text-slate-400">NONAKTIF</div>
          <div className="mt-1 text-2xl font-bold text-slate-100">{stats.inactive}</div>
          <div className="mt-1 text-sm text-slate-300">Sekolah nonaktif</div>
        </div>
      </div>

      <div className="rounded-3xl bg-slate-900/60 p-6 shadow-xl border border-slate-700/50 backdrop-blur-2xl space-y-4">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div className="min-w-0">
            <div className="text-sm font-semibold text-slate-100">Tenant Registry (Realtime)</div>
            <div className="mt-1 text-sm text-slate-300">
              Sumber data: <span className="font-semibold text-slate-200">schools</span>
            </div>
          </div>
          <input
            value={q}
            onChange={(e) => setQ(e.target.value)}
            placeholder="Cari schoolId / nama / NPSN / email..."
            className="w-full sm:w-80 rounded-xl border border-slate-700/50 bg-slate-950/30 px-4 py-2 text-sm text-slate-100 placeholder:text-slate-500"
          />
        </div>

        {error ? (
          <div className="rounded-2xl border border-red-500/30 bg-red-500/10 p-4 text-sm text-red-100">
            {error}
          </div>
        ) : null}

        <div className="overflow-x-auto">
          <table className="min-w-[920px] w-full border-separate border-spacing-y-2">
            <thead>
              <tr className="text-left text-xs font-semibold tracking-widest text-slate-400">
                <th className="px-3 py-2">SCHOOL ID</th>
                <th className="px-3 py-2">NAMA</th>
                <th className="px-3 py-2">NPSN</th>
                <th className="px-3 py-2">KECAMATAN</th>
                <th className="px-3 py-2">UPDATED</th>
                <th className="px-3 py-2 text-right">STATUS</th>
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr>
                  <td colSpan={6} className="px-3 py-6 text-sm text-slate-300">
                    Memuat...
                  </td>
                </tr>
              ) : filtered.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-3 py-6 text-sm text-slate-300">
                    Data tidak ditemukan.
                  </td>
                </tr>
              ) : (
                filtered.map((r) => {
                  const disabled = busyId === r.schoolId;
                  return (
                    <tr key={r.schoolId} className="bg-slate-950/20 border border-slate-700/40">
                      <td className="px-3 py-3 text-sm font-semibold text-slate-100">
                        {r.schoolId}
                        <div className="mt-1 text-xs text-slate-400">{r.authEmail || r.adminEmail || "-"}</div>
                      </td>
                      <td className="px-3 py-3 text-sm text-slate-100">
                        {r.name || "-"}
                        <div className="mt-1 text-xs text-slate-400">{r.backupEmail || "-"}</div>
                      </td>
                      <td className="px-3 py-3 text-sm text-slate-100">{r.npsn || "-"}</td>
                      <td className="px-3 py-3 text-sm text-slate-100">{r.district || "-"}</td>
                      <td className="px-3 py-3 text-sm text-slate-100">{formatTs(r.updatedAt || r.createdAt)}</td>
                      <td className="px-3 py-3 text-right">
                        <button
                          type="button"
                          disabled={disabled}
                          onClick={() => toggleActive(r.schoolId, !r.isActive)}
                          className={`inline-flex items-center justify-center rounded-xl px-4 py-2 text-sm font-semibold transition border ${
                            r.isActive
                              ? "border-emerald-400/30 bg-emerald-500/15 text-emerald-100 hover:bg-emerald-500/20"
                              : "border-red-400/30 bg-red-500/15 text-red-100 hover:bg-red-500/20"
                          } ${disabled ? "opacity-60 cursor-not-allowed" : ""}`}
                        >
                          {r.isActive ? "Aktif" : "Nonaktif"}
                        </button>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

"use client";

import Image from "next/image";
import { useState } from "react";
import { useRouter } from "next/navigation";
import { signInWithEmailAndPassword, updatePassword } from "firebase/auth";
import { auth } from "@/lib/firebase/client";
import { Eye, EyeOff } from "lucide-react";

export default function LoginPage() {
  const router = useRouter();
  const [identifier, setIdentifier] = useState("");
  const [password, setPassword] = useState("admin123");
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const [mustChangeGate, setMustChangeGate] = useState(false);
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [changingPassword, setChangingPassword] = useState(false);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      const raw = String(identifier || "").trim();
      if (!raw || !password) {
        setError("NPSN/Email dan password wajib diisi.");
        setLoading(false);
        return;
      }

      // Format login: Jika tidak ada '@', asumsikan NPSN sekolah
      const emailLower = raw.includes("@") ? raw.toLowerCase() : `${raw}@edulock.local`;

      try {
        await signInWithEmailAndPassword(auth, emailLower, password);
      } catch (signInErr: any) {
        if (signInErr.code === "auth/invalid-credential" && password === "admin123" && !raw.includes("@")) {
          // Coba bootstrap akun jika belum ada
          const res = await fetch("/api/bootstrap", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ npsn: raw })
          });

          if (res.ok) {
            // Coba login lagi setelah berhasil dibuat
            await signInWithEmailAndPassword(auth, emailLower, password);
          } else {
            const errData = await res.json().catch(() => ({}));
            throw new Error(errData.error || "Gagal menyiapkan akun baru. Hubungi super admin.");
          }
        } else {
          throw signInErr;
        }
      }

      if (password === "admin123") {
        setMustChangeGate(true);
        setNewPassword("");
        setConfirmPassword("");
        return;
      }

      // Redirect diurus otomatis oleh AuthProvider jika tidak harus ganti password
    } catch (err: any) {
      const code = String(err?.code || "");
      if (code === "auth/invalid-credential" || code === "auth/wrong-password") {
        setError("Email atau Password salah.");
      } else if (code === "auth/user-not-found") {
        setError("Akun belum terdaftar.");
      } else {
        setError(`Gagal masuk: ${err?.message || err}`);
      }
    } finally {
      setLoading(false);
    }
  };

  const handleChangePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");

    const next = String(newPassword || "");
    const confirm = String(confirmPassword || "");
    if (next.length < 6) {
      setError("Password baru minimal 6 karakter.");
      return;
    }
    if (next === "admin123") {
      setError("Password baru tidak boleh sama dengan admin123.");
      return;
    }
    if (next !== confirm) {
      setError("Konfirmasi password tidak sama.");
      return;
    }

    setChangingPassword(true);
    try {
      if (!auth.currentUser) throw new Error("User tidak terautentikasi.");
      await updatePassword(auth.currentUser, next);

      setMustChangeGate(false);
      setNewPassword("");
      setConfirmPassword("");
      // Redirect diurus otomatis oleh AuthProvider
    } catch (e: any) {
      setError(`Gagal ubah password: ${String(e?.message || e)}`);
    } finally {
      setChangingPassword(false);
    }
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-slate-950 px-4 py-12 sm:px-6 lg:px-8">
      <div className="w-full max-w-md">
        <div className="rounded-2xl border border-white/10 bg-slate-900/60 p-8 shadow-xl backdrop-blur">
          <div className="flex flex-col items-center">
            <div className="flex h-24 w-24 items-center justify-center rounded-2xl bg-gradient-to-br from-blue-500/20 to-indigo-600/20 mb-4 shadow-lg border border-white/10 overflow-hidden relative">
              <Image
                src="/PortalKita.png"
                alt="Logo PortalKita"
                fill
                className="object-contain p-2"
                priority
              />
            </div>
            <p className="text-center text-sm font-semibold text-slate-200">
              SELAMAT DATANG DI PORTALKITA
            </p>
            <h1 className="text-center text-2xl font-bold tracking-tight text-white">Login Portal</h1>
          </div>

          {error && (
            <div className="mt-6 rounded-md border border-red-500/20 bg-red-500/10 p-3 text-sm text-red-200">
              {error}
            </div>
          )}

          {mustChangeGate ? (
            <form onSubmit={handleChangePassword} className="mt-6 space-y-4">
              <div className="rounded-md border border-amber-500/20 bg-amber-500/10 p-3 text-sm text-amber-200">
                Demi keamanan, Anda wajib mengganti password pada login pertama.
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-200">Password Baru</label>
                <input
                  value={newPassword}
                  onChange={(e) => setNewPassword(e.target.value)}
                  disabled={changingPassword}
                  type="password"
                  className="mt-2 w-full rounded-lg border border-white/10 bg-slate-800 px-4 py-3 text-sm text-white placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                  placeholder="Minimal 6 karakter"
                  autoComplete="new-password"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-200">Konfirmasi Password Baru</label>
                <input
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  disabled={changingPassword}
                  type="password"
                  className="mt-2 w-full rounded-lg border border-white/10 bg-slate-800 px-4 py-3 text-sm text-white placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                  placeholder="Ulangi password baru"
                  autoComplete="new-password"
                  required
                />
              </div>

              <button
                type="submit"
                disabled={changingPassword}
                className="mt-2 w-full rounded-lg bg-indigo-600 px-4 py-3 text-sm font-semibold text-white hover:bg-indigo-700 disabled:opacity-50 transition-colors"
              >
                {changingPassword ? "Menyimpan..." : "Simpan Password & Lanjutkan"}
              </button>
            </form>
          ) : (
            <form onSubmit={handleLogin} className="mt-6 space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-200">NPSN Sekolah / Email Super Admin</label>
                <input
                  value={identifier}
                  onChange={(e) => setIdentifier(e.target.value)}
                  disabled={loading}
                  className="mt-2 w-full rounded-lg border border-white/10 bg-slate-800 px-4 py-3 text-sm text-white placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                  placeholder="NPSN atau Email"
                  autoComplete="username"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-200">Password</label>
                <div className="relative mt-2">
                  <input
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    disabled={loading}
                    type={showPassword ? "text" : "password"}
                    className="w-full rounded-lg border border-white/10 bg-slate-800 px-4 py-3 pr-12 text-sm text-white placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                    placeholder="admin123"
                    autoComplete="current-password"
                    required
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword((v) => !v)}
                    className="absolute inset-y-0 right-0 flex items-center px-3 text-slate-200 hover:text-white disabled:opacity-60"
                    disabled={loading}
                    aria-label={showPassword ? "Sembunyikan password" : "Tampilkan password"}
                  >
                    {showPassword ? <EyeOff className="h-5 w-5" /> : <Eye className="h-5 w-5" />}
                  </button>
                </div>
              </div>

              <button
                type="submit"
                disabled={loading}
                className="mt-2 w-full rounded-lg bg-indigo-600 px-4 py-3 text-sm font-semibold text-white hover:bg-indigo-700 disabled:cursor-not-allowed disabled:opacity-50 transition-colors"
              >
                {loading ? "Memproses..." : "Masuk"}
              </button>

              <div className="mt-4 text-center text-xs text-slate-400">
                Login admin sekolah menggunakan username NPSN dan password awal admin123.
              </div>
            </form>
          )}

          <div className="mt-6 text-center">
            <button
              type="button"
              disabled={loading}
              className="text-sm font-semibold text-slate-200 hover:text-white disabled:opacity-60"
            >
              Lupa Password?
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

