"use client";

import Link from "next/link";
import { useEffect, useMemo, useState } from "react";
import { onValue, ref, update, set, query, limitToLast } from "firebase/database";
import { rtdb as db, auth } from "@/lib/firebase/client";
import { SEED_RAW } from "./seedData";
import { callSuperAdminApi } from "@/lib/callSuperAdminApi";
import { useAuthStore } from "@/store/useAuthStore";
import { Search, Lock, Download } from "lucide-react";

type SuperDbSection = "schools" | "admins" | "principals" | "monitoring";

const SUPER_ADMIN_DATABASE_MENU = [
  ["schools", "Sekolah & Tenant"],
  ["admins", "Admin Sekolah"],
  ["principals", "Akun Kepala Sekolah"],
  ["monitoring", "Monitoring Akun & Layanan"],
] as const;

type SuperSchoolRow = {
  schoolId: string;
  name: string;
  district: string;
  npsn: string;
  authEmail: string;
  adminEmail: string;
  backupEmail: string;
  isActive: boolean;
  adminAccessActive: boolean;
  createdAt?: number | null;
  updatedAt?: number | null;
};

type PrincipalRow = {
  username: string;
  name: string;
  schoolId: string;
  schoolName: string;
  npsn?: string;
  isActive: boolean;
  lastLoginAt?: number | null;
  deviceId?: string;
};

type SecurityLog = {
  id: string;
  timestamp: number | null;
  username: string;
  accountType: string;
  activity: string;
};

export default function StandaloneDatabasePage() {
  const { user, loading: isAuthLoading } = useAuthStore();
  const [superSection, setSuperSection] = useState<SuperDbSection>("schools");

  const [superSchools, setSuperSchools] = useState<SuperSchoolRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [superSaving, setSuperSaving] = useState(false);
  const [statusMsg, setStatusMsg] = useState<{ type: "" | "success" | "error"; text: string }>({ type: "", text: "" });

  const [superSchoolForm, setSuperSchoolForm] = useState({
    schoolId: "",
    name: "",
    district: "",
    npsn: "",
    authEmail: "",
    adminEmail: "",
    backupEmail: "",
    isActive: true,
  });

  const [superPrincipals, setSuperPrincipals] = useState<PrincipalRow[]>([]);
  const [principalQuery, setPrincipalQuery] = useState("");
  const [principalEditing, setPrincipalEditing] = useState("");
  const [principalSaving, setPrincipalSaving] = useState(false);
  const [principalForm, setPrincipalForm] = useState({
    username: "",
    name: "",
    schoolId: "",
    schoolName: "",
    password: "",
    isActive: true,
  });

  const [securityLogs, setSecurityLogs] = useState<SecurityLog[]>([]);

  const [adminSchoolForm, setAdminSchoolForm] = useState({
    schoolId: "",
    schoolName: "",
    npsn: "",
    authEmail: "",
    adminEmail: "",
    backupEmail: "",
    schoolActive: true,
    adminAccessActive: true,
  });

  const superSchoolAdmins = useMemo(() => {
    return superSchools.map(s => ({
      schoolId: s.schoolId,
      schoolName: s.name,
      npsn: s.npsn,
      loginIdentifier: s.authEmail || s.adminEmail || "",
      runtimeEmail: "",
      schoolActive: s.isActive,
      accessActive: s.adminAccessActive,
      runtimeLastLoginAt: null,
      runtimeMustChangePassword: false
    }));
  }, [superSchools]);

  const openAdminSchoolEditor = (school: SuperSchoolRow) => {
    setAdminSchoolForm({
      schoolId: school.schoolId,
      schoolName: school.name,
      npsn: school.npsn,
      authEmail: school.authEmail,
      adminEmail: school.adminEmail,
      backupEmail: school.backupEmail,
      schoolActive: school.isActive,
      adminAccessActive: school.adminAccessActive,
    });
  };

  const saveAdminSchoolRegistry = async () => {
    if (!adminSchoolForm.schoolId) {
      setStatusMsg({ type: "error", text: "Pilih sekolah terlebih dahulu." });
      return;
    }
    setSuperSaving(true);
    setStatusMsg({ type: "", text: "" });
    try {
      await callSuperAdminApi("POST", {
        action: "save-school",
        school: {
          schoolId: adminSchoolForm.schoolId,
          name: adminSchoolForm.schoolName,
          npsn: adminSchoolForm.npsn,
          authEmail: adminSchoolForm.authEmail,
          adminEmail: adminSchoolForm.adminEmail,
          backupEmail: adminSchoolForm.backupEmail,
          isActive: adminSchoolForm.schoolActive,
          adminAccessActive: adminSchoolForm.adminAccessActive,
        },
      });
      setStatusMsg({ type: "success", text: "Login Admin berhasil disimpan." });
    } catch (e: any) {
      setStatusMsg({ type: "error", text: String(e?.message || e || "Gagal menyimpan login admin.") });
    } finally {
      setSuperSaving(false);
    }
  };

  useEffect(() => {
    if (isAuthLoading) return;
    setLoading(true);
    const unsub = onValue(
      ref(db, "schools"),
      (snapshot) => {
        const data = snapshot.val();
        if (!data || typeof data !== "object") {
          setSuperSchools([]);
          setLoading(false);
          return;
        }

        const list: SuperSchoolRow[] = Object.entries(data).map(([key, v]: any) => ({
          schoolId: String(v?.schoolId || key).trim().toLowerCase(),
          name: v?.name ? String(v.name).trim() : "",
          district: v?.district ? String(v.district).trim() : "",
          npsn: v?.npsn ? String(v.npsn).trim() : "",
          authEmail: v?.authEmail ? String(v.authEmail).trim() : "",
          adminEmail: v?.adminEmail ? String(v.adminEmail).trim() : "",
          backupEmail: v?.backupEmail ? String(v.backupEmail).trim() : "",
          isActive: v?.isActive !== false,
          adminAccessActive: v?.adminAccessActive !== false,
          createdAt: typeof v?.createdAt === "number" ? v.createdAt : null,
          updatedAt: typeof v?.updatedAt === "number" ? v.updatedAt : null,
        }));
        list.sort((a, b) => String(a.name || a.schoolId).localeCompare(String(b.name || b.schoolId)));
        setSuperSchools(list);
        setLoading(false);
      },
      (error) => {
        console.error("RTDB error schools:", error);
        setLoading(false);
      }
    );

    const unsubPrincipals = onValue(
      ref(db, "principals"),
      (snapshot) => {
        const data = snapshot.val();
        if (!data || typeof data !== "object") {
          setSuperPrincipals([]);
          return;
        }
        const list: PrincipalRow[] = Object.values(data).map((v: any) => ({
          username: v?.username || "",
          name: v?.name || "",
          schoolId: v?.schoolId || "",
          schoolName: v?.schoolName || "",
          npsn: v?.npsn || "",
          isActive: v?.isActive !== false,
          lastLoginAt: v?.lastLoginAt || null,
          deviceId: v?.deviceId || "",
        }));
        list.sort((a, b) => a.username.localeCompare(b.username));
        setSuperPrincipals(list);
      },
      (error) => {
        console.error("RTDB error principals:", error);
      }
    );

    const unsubSecurityLogs = onValue(
      query(ref(db, "super/security_logs"), limitToLast(200)),
      (snapshot) => {
        const data = snapshot.val();
        if (!data || typeof data !== "object") {
          setSecurityLogs([]);
          return;
        }
        const list: SecurityLog[] = Object.entries(data).map(([key, v]: any) => ({
          id: key,
          timestamp: v?.timestamp || null,
          username: v?.username || "",
          accountType: v?.accountType || "",
          activity: v?.activity || "",
        }));
        list.sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0));
        setSecurityLogs(list);
      }
    );

    return () => {
      unsub();
      unsubPrincipals();
      unsubSecurityLogs();
