'use client';

import { useEffect } from 'react';
import { useRouter, usePathname } from 'next/navigation';
import { onAuthStateChanged } from 'firebase/auth';
import { auth } from '@/lib/firebase/client';
import { useAuthStore, PortalUser } from '@/store/useAuthStore';

export default function AuthProvider({ children }: { children: React.ReactNode }) {
  const { setUser, setLoading, loading, user } = useAuthStore();
  const router = useRouter();
  const pathname = usePathname();

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
      if (currentUser) {
        try {
          const token = await currentUser.getIdTokenResult();
          const role = (token.claims.role as any) || 'admin';
          const schoolId = token.claims.schoolId as string | undefined;

          const portalUser: PortalUser = {
            id: currentUser.uid,
            name: currentUser.displayName || currentUser.email || 'User',
            email: currentUser.email || '',
            role: role,
            schoolId: schoolId,
          };
          setUser(portalUser);
        } catch (e) {
          setUser(null);
        }
      } else {
        setUser(null);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, [setUser, setLoading]);

  useEffect(() => {
    if (!loading) {
      if (!user && pathname.startsWith('/dashboard')) {
        router.push('/login');
      }

      if (user && (pathname === '/login' || pathname === '/')) {
        if (user.role === 'super_admin') {
          router.push('/dashboard/super');
        } else {
          router.push('/dashboard');
        }
      }
    }
  }, [user, loading, pathname, router]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#0f172a]">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  return <>{children}</>;
}

import { auth } from "./firebase/client";

type DatabaseAction = "create" | "update" | "delete" | "delete-all";

interface DatabasePayload {
  action: DatabaseAction;
  tab: string;
  data?: any;
  id?: string;
}

export async function callAdminDatabaseApi(payload: DatabasePayload) {
  const currentUser = auth.currentUser;
  if (!currentUser) {
    throw new Error("Sesi tidak aktif. Silakan login ulang.");
  }

  const idToken = await currentUser.getIdToken();
  const response = await fetch("/api/admin/database", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${idToken}`,
    },
    body: JSON.stringify(payload),
  });

  const result = await response.json().catch(() => ({}));
  if (!response.ok || result?.success === false) {
    throw new Error(result?.message || "Terjadi kesalahan pada server");
  }

  return result;
}

"use client";

import { auth, functions } from "@/lib/firebase/client";
import { httpsCallable } from "firebase/functions";

// Pemetaan dari action string lama ke nama Cloud Function yang baru dibuat
const ACTION_TO_FUNCTION: Record<string, string> = {
  "toggle-school-active": "toggleSchoolActive",
  "save-school": "saveSchool",
  "save-principal": "savePrincipal",
  "reset-principal-device": "resetPrincipalDevice",
  "save-global-config": "saveGlobalConfig",
  "create-broadcast": "createBroadcast",
  "delete-broadcast": "deleteBroadcast",
  "create-sync-job": "createSyncJob",
  "set-sync-job-status": "setSyncJobStatus",
  "create-support-request": "createSupportRequest",
  "set-support-request-status": "setSupportRequestStatus",
  "delete-support-request": "deleteSupportRequest",
};

export async function callSuperAdminApi(
  method: "POST" | "PUT" | "DELETE",
  payload: Record<string, unknown>
) {
  const currentUser = auth.currentUser;
  if (!currentUser) {
    throw new Error("Sesi tidak aktif. Silakan login ulang.");
  }

  const action = typeof payload.action === "string" ? payload.action : "";
  const functionName = ACTION_TO_FUNCTION[action];

  if (!functionName) {
    throw new Error(`Aksi '${action}' belum didukung di Cloud Functions.`);
  }

  try {
    const callable = httpsCallable(functions, functionName);
    const result = await callable(payload);
    const data = result.data as any;

    if (data && data.success === false) {
      throw new Error(data.message || "Permintaan super admin gagal diproses.");
    }

    return data;
  } catch (error: any) {
    // Tangkap HttpsError dari Firebase Functions
    throw new Error(error.message || "Permintaan super admin gagal diproses.");
  }
}

